DELETE FROM clinlims.notebook_page
WHERE title = 'Virus Isolation' AND page_order = 10
AND notebook_id IN (
    SELECT id FROM clinlims.notebook
    WHERE title = 'Virology and Vaccine Unit' AND is_template = true
);

DELETE FROM clinlims.notebook_page
WHERE title = 'Virus Isolation' AND page_order = 10
AND notebook_id IN (
    SELECT id FROM clinlims.notebook
    WHERE title LIKE '%Virology%' AND is_template = false
);
